#!/usr/bin/env bash
# =============================================================================
#  migrate_views.sh
#  Refactoriza backend/maestros/views.py en el paquete views/
#
#  Uso desde la raíz del proyecto en WSL2:
#    chmod +x migrate_views.sh && ./migrate_views.sh
# =============================================================================

set -e  # Detener si cualquier comando falla

# ── Configuración ─────────────────────────────────────────────────────────────
PROJECT_ROOT="$(pwd)"
VIEWS_DIR="$PROJECT_ROOT/backend/maestros/views"
OLD_VIEWS="$PROJECT_ROOT/backend/maestros/views.py"
URLS_FILE="$PROJECT_ROOT/backend/pos_core/urls.py"
BACKUP_DIR="$PROJECT_ROOT/_backup_views_$(date +%Y%m%d_%H%M%S)"

# ── Colores ───────────────────────────────────────────────────────────────────
GREEN='\033[0;32m'
YELLOW='\033[1;33m'
RED='\033[0;31m'
NC='\033[0m'

ok()   { echo -e "${GREEN}  ✓${NC} $1"; }
warn() { echo -e "${YELLOW}  ⚠${NC} $1"; }
err()  { echo -e "${RED}  ✗${NC} $1"; exit 1; }

echo ""
echo "========================================"
echo "  Migración de views.py → views/"
echo "========================================"
echo ""

# ── Validar que estamos en el lugar correcto ──────────────────────────────────
[ -f "$PROJECT_ROOT/backend/maestros/views.py" ] \
  || [ -d "$PROJECT_ROOT/backend/maestros/views" ] \
  || err "No se encontró backend/maestros/views.py ni views/. Ejecutá el script desde la raíz del proyecto."

[ -f "$PROJECT_ROOT/backend/pos_core/urls.py" ] \
  || err "No se encontró backend/pos_core/urls.py. ¿Estás en la raíz del proyecto?"

# ── Backup ────────────────────────────────────────────────────────────────────
mkdir -p "$BACKUP_DIR"

if [ -f "$OLD_VIEWS" ]; then
    cp "$OLD_VIEWS" "$BACKUP_DIR/views.py"
    ok "Backup de views.py guardado en $BACKUP_DIR/"
fi

cp "$URLS_FILE" "$BACKUP_DIR/urls.py"
ok "Backup de urls.py guardado en $BACKUP_DIR/"

# ── Crear directorio views/ ───────────────────────────────────────────────────
if [ -f "$OLD_VIEWS" ]; then
    rm "$OLD_VIEWS"
    ok "views.py eliminado (hay backup)"
fi

mkdir -p "$VIEWS_DIR"
ok "Directorio views/ creado"

echo ""
echo "Escribiendo archivos..."
echo ""

# ── Función para decodificar y escribir ───────────────────────────────────────
write_file() {
    local path="$1"
    local content_b64="$2"
    echo "$content_b64" | base64 -d > "$path"
    ok "$path"
}

write_file "$VIEWS_DIR/utils.py" \
  ""

write_file "$VIEWS_DIR/sync.py" \
  ""

write_file "$VIEWS_DIR/auth.py" \
  ""

write_file "$VIEWS_DIR/cajas.py" \
  ""

write_file "$VIEWS_DIR/ventas.py" \
  ""

write_file "$VIEWS_DIR/clientes.py" \
  ""

write_file "$VIEWS_DIR/stock.py" \
  ""

write_file "$VIEWS_DIR/compras.py" \
  ""

write_file "$VIEWS_DIR/cta_cte.py" \
  ""

write_file "$VIEWS_DIR/informes.py" \
  ""

write_file "$VIEWS_DIR/configuracion.py" \
  ""

write_file "$VIEWS_DIR/__init__.py" \
  ""

write_file "$URLS_FILE" \
  ""


echo ""
echo "========================================"
ok "Migración completada."
echo ""
echo "Estructura generada:"
find "$VIEWS_DIR" -name "*.py" | sort | while read f; do
    lines=$(wc -l < "$f")
    printf "  %-45s %d líneas\n" "$(basename $f)" "$lines"
done
echo ""
echo "Siguiente paso — verificar que Django levanta:"
echo ""
echo "  docker compose exec web python manage.py check"
echo ""
echo "Si algo falla, el backup está en:"
echo "  $BACKUP_DIR"
echo "========================================"
